        arr[0] = 1;
        arr[n + 1] = 1;
        for (int i = 0; i < n; i++) arr[i + 1] = nums[i];
        return dp(arr, 1, n);
    }

    private int dp(int[] arr, int left, int right) {
        if (left > right) return 0;
        int maxCoins = 0;
        for (int i = left; i <= right; i++) {
            int coins = arr[left - 1] * arr[i] * arr[right + 1];
            maxCoins = Math.max(maxCoins, coins + dp(arr, left, i - 1) + dp(arr, i + 1, right));
        }
        return maxCoins;
    }
}

class Solution {
    public int maxCoins(int[] nums) {
        int n = nums.length;
        int[] arr = new int[n + 2];
        arr[0] = 1;
        arr[n + 1] = 1;
        for (int i = 0; i < n; i++) arr[i + 1] = nums[i];
        int[][] memo = new int[n + 2][n + 2];
        for (int[] row : memo) Arrays.fill(row, -1);
        return dp(arr, 1, n, memo);
    }

    private int dp(int[] arr, int left, int right, int[][] memo) {
        if (left > right) return 0;
        if (memo[left][right] != -1) return memo[left][right];
        int maxCoins = 0;
        for (int i = left; i <= right; i++) {
            int coins = arr[left - 1] * arr[i] * arr[right + 1];
            maxCoins = Math.max(maxCoins, coins + dp(arr, left, i - 1, memo) + dp(arr, i + 1, right, memo));
        }
        return memo[left][right] = maxCoins;
    }
}

class Solution {
    public int maxCoins(int[] nums) {
        int n = nums.length;
        int[] arr = new int[n + 2];
        arr[0] = 1;
        arr[n + 1] = 1;
        for (int i = 0; i < n; i++) arr[i + 1] = nums[i];
        int[][] dp = new int[n + 2][n + 2];
        for (int len = 1; len <= n; len++) {
            for (int left = 1; left <= n - len + 1; left++) {
                int right = left + len - 1;
                for (int k = left; k <= right; k++) {
                    dp[left][right] = Math.max(dp[left][right],
                        dp[left][k - 1] + arr[left - 1] * arr[k] * arr[right + 1] + dp[k + 1][right]);
                }
            }
        }
        return dp[1][n];
    }
}
